// Structure definitions
struct Student {
    int studentID;      // PRIMARY KEY
    char name[50];      // NOT NULL
    char email[50];    // UNIQUE
    int age;           // CHECK: age >= 18
};

// Function to validate INSERT operation
int validateInsert(struct Student s) {
    // Entity Integrity: Check primary key is not NULL
    if (s.studentID == NULL) {
        printf("Error: Primary key cannot be NULL\n");
        return 0;
    }

    // Entity Integrity: Check for duplicate primary key
    if (searchPrimaryKey(s.studentID)) {
        printf("Error: Duplicate primary key\n");
        return 0;
    }

    // Domain Integrity: NOT NULL check
    if (s.name == NULL || strlen(s.name) == 0) {
        printf("Error: Name cannot be NULL\n");
        return 0;
    }

    // Domain Integrity: CHECK constraint
    if (s.age < 18) {
        printf("Error: Age must be >= 18\n");
        return 0;
    }

    // Domain Integrity: UNIQUE constraint
    if (searchEmail(s.email)) {
        printf("Error: Email already exists\n");
        return 0;
    }

    return 1;  // All constraints satisfied
}

// Function to validate foreign key reference
int validateForeignKey(int courseID) {
    // Referential Integrity: Check if course exists
    if (!searchPrimaryKeyCourse(courseID)) {
        printf("Error: Invalid course reference\n");
        return 0;
    }
    return 1;
}

-- Add a CHECK constraint to existing table
ALTER TABLE Employee
ADD CONSTRAINT SalaryCheck CHECK (Salary >= 5000);

-- Add UNIQUE constraint to existing column
ALTER TABLE Employee
ADD CONSTRAINT EmailUnique UNIQUE (Email);

-- Add FOREIGN KEY to existing table
ALTER TABLE Employee
ADD CONSTRAINT DeptFK FOREIGN KEY (DeptID) 
REFERENCES Department(DeptID) ON DELETE SET NULL;

-- Drop a constraint
ALTER TABLE Employee
DROP CONSTRAINT SalaryCheck;

-- Disable constraint temporarily
ALTER TABLE Employee
NOCHECK CONSTRAINT SalaryCheck;

-- Re-enable constraint
ALTER TABLE Employee
WITH CHECK CHECK CONSTRAINT SalaryCheck;

-- Add NOT NULL to existing column (two-step process)
ALTER TABLE Employee
ALTER COLUMN Email VARCHAR(50) NOT NULL;

-- View all constraints on a table
SELECT * FROM INFORMATION_SCHEMA.TABLE_CONSTRAINTS
WHERE TABLE_NAME = 'Employee';
